import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

cuda_src = """
#include <torch/extension.h>
#include <cublas_v2.h>

static cublasHandle_t handle = nullptr;

torch::Tensor cublas_gemm(torch::Tensor A, torch::Tensor B) {
    if (!handle) cublasCreate(&handle);
    int M = A.size(0), K = A.size(1), N = B.size(1);
    auto C = torch::empty({M, N}, A.options());
    float alpha = 1.0f, beta = 0.0f;
    // cuBLAS uses column-major: C = A @ B -> C^T = B^T @ A^T
    cublasSgemm(handle, CUBLAS_OP_N, CUBLAS_OP_N,
                N, M, K, &alpha,
                B.data_ptr<float>(), N,
                A.data_ptr<float>(), K,
                &beta, C.data_ptr<float>(), N);
    return C;
}
"""

cpp_src = "torch::Tensor cublas_gemm(torch::Tensor A, torch::Tensor B);"

gemm_module = load_inline(name='cublas_gemm', cpp_sources=cpp_src,
                          cuda_sources=cuda_src, extra_ldflags=['-lcublas'],
                          functions=['cublas_gemm'])

class ModelNew(nn.Module):
    def __init__(self):
        super().__init__()

    def forward(self, A, B):
        return gemm_module.cublas_gemm(A.contiguous(), B.contiguous())
